#include <stdio.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <unistd.h>

int main(void) {
    int fd = shm_open("/kf_shm_create", O_CREAT | O_RDWR, 0644);
    ftruncate(fd, 4096);

    int *ptr = (int *)mmap(NULL, 4096, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);

    *ptr = 42;
    printf("Shared value: %d\n", *ptr);

    munmap(ptr, 4096);
    shm_unlink("/kf_shm_create");
    return 0;
}

