/* == EXEMPLE =======================================
 * Creer un segment shm et y stocker un double
 * ================================================= */
void example_shm_double(void) {
    int fd = shm_open("/kf_ex_double", O_CREAT|O_RDWR, 0644);
    ftruncate(fd, 4096);
    double *p = (double *)mmap(NULL, 4096, PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);
    *p = 3.14;
    printf("Shared: %.2f\n", *p);
    munmap(p, 4096);
    shm_unlink("/kf_ex_double");
}
